account_groups_by_name = {}
[{:name=>"Checking Accounts", :sort_order=>1}, {:name=>"Credit Cards", :sort_order=>2}].each do |ag|
  grp = user.account_groups.find_or_create_by!(name: ag[:name]) { |g| g.sort_order = ag[:sort_order] || 0 }
  account_groups_by_name[ag[:name]] = grp
end
accounts_by_name = {}
[{:name=>"Primary Checking", :account_type=>"checking", :balance=>1646.12, :account_group_name=>"Checking Accounts"}, {:name=>"Credit Card", :account_type=>"credit", :balance=>1757.04, :account_group_name=>"Credit Cards"}].each do |acc|
