    user.goals.delete_all
    [{:category_name=>"Miscellaneous", :goal_type=>"needed_for_spending", :target_amount=>300.0, :target_date=>nil}, {:category_name=>"Subscriptions", :goal_type=>"needed_for_spending", :target_amount=>100.0, :target_date=>nil}, {:category_name=>"Utilities", :goal_type=>"needed_for_spending", :target_amount=>250.0, :target_date=>nil}, {:category_name=>"Groceries", :goal_type=>"needed_for_spending", :target_amount=>600.0, :target_date=>nil}].each do |g_row|
      cat = categories_by_name[g_row[:category_name]]
      next unless cat
      user.goals.create!(category: cat, goal_type: g_row[:goal_type], target_amount: g_row[:target_amount], target_date: g_row[:target_date].present? ? Date.parse(g_row[:target_date]) : nil)
    end

    user.accounts.find_each(&:recalculate_balance!)
    budget.budget_months.find_each { |bm| BudgetService.calculate_budget_month_available(bm) }
